def f(X, model = model, pdf = pdf, scoreind = 1, threshold = threshold, x0 = x0):
    return model.predict_proba(X)[:,scoreind]*(pdf(X)>=threshold)  + model.predict_proba(x0)[:,scoreind]*(pdf(X)<threshold) 


